const rows = $input.all().map(i => i.json);
if (rows.length === 0) return [];

const streamId = $('Webhook: Stream Ended').item.json.body.record.id;
const highlights = [];

// 1. Viewer milestone detection
const milestones = [100, 200, 500, 1000];
const crossed = new Set();
for (const row of rows) {
  for (const m of milestones) {
    if (row.viewer_count >= m && !crossed.has(m)) {
      crossed.add(m);
      highlights.push({
        stream_id: streamId,
        occurred_at: row.recorded_at,
        reason: `Viewer count crossed ${m}`
      });
    }
  }
}

// 2. Chat spike detection (2x rolling average)
const msgCounts = rows.map(r => r.message_count_per_minute);
const totalAvg = msgCounts.reduce((a, b) => a + b, 0) / (msgCounts.length || 1);
const threshold = Math.max(totalAvg * 2, 5); // at least 5 msgs/min to qualify

for (const row of rows) {
  if (row.message_count_per_minute >= threshold) {
    highlights.push({
      stream_id: streamId,
      occurred_at: row.recorded_at,
      reason: `High chat activity (${row.message_count_per_minute} msgs/min)`
    });
  }
}

return highlights.map(h => ({ json: h }));
